@page "/apply"
@rendermode InteractiveServer
@namespace sv_d79a744593ce4e13937ae6e041bf41f1.Components.Pages.Apply

@using sv_d79a744593ce4e13937ae6e041bf41f1.Models

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   StepNames="stepNames"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="() => AdvanceStep(0)" />
            break;

        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="() => AdvanceStep(1)"
                             OnBack="() => GoToStep(0)" />
            break;

        case 2:
            <ReferencesStep References="references"
                            OnNext="() => AdvanceStep(2)"
                            OnBack="() => GoToStep(1)" />
            break;

        case 3:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="() => AdvanceStep(3)"
                             OnBack="() => GoToStep(2)" />
            break;

        case 4:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        IsSubmitted="isSubmitted"
                        ApplicationId="applicationId"
                        OnSubmit="SubmitApplication"
                        OnBack="() => GoToStep(3)"
                        OnEditStep="GoToStep" />
            break;
    }
</div>

@code {
    private static readonly IReadOnlyList<string> stepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int currentStep;
    private readonly HashSet<int> completedSteps = new();

    // Form state
    private readonly PersonalInfoModel personalInfo = new();
    private readonly List<WorkEntryModel> workEntries = [new()];
    private readonly List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    // Submission state
    private bool isSubmitted;
    private int applicationId;

    private void AdvanceStep(int completedStep)
    {
        completedSteps.Add(completedStep);
        currentStep = completedStep + 1;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        isSubmitted = true;
    }
}

